import React from 'react';
import ReactDOM from 'react-dom/client';

// 1. Importación de los estilos globales.
// Esta línea es fundamental para que Tailwind funcione.
import './index.css';

// 2. Importación del componente principal App.
// Esta línea asume que tu archivo se llama `App.js` o `App.jsx`
// y se encuentra en la misma carpeta `src`.
import App from './App';

// 3. Renderizado de la aplicación en el DOM.
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
